class AuthenticationInterceptor(grpc.ServerInterceptor):
    """
    Server interceptor that validates authentication tokens from metadata.

    Extracts the 'authorization' metadata key and validates the bearer token.
    Certain paths can be configured to bypass authentication.
    """

    METADATA_KEY = "authorization"
    BEARER_PREFIX = "Bearer "

    def __init__(
        self,
        token_validator: TokenValidator,
        bypass_config: AuthBypassConfig = None,
    ):
        self._validator = token_validator
        self._bypass_config = bypass_config or AuthBypassConfig()
        logger.info("AuthenticationInterceptor initialized")
        logger.info(f"Auth bypass exact paths: {self._bypass_config.exact_paths}")
        logger.info(f"Auth bypass prefixes: {self._bypass_config.prefix_paths}")
        logger.info(f"Auth bypass operational: {self._bypass_config.operational_prefixes}")

        # Log security warnings for dangerous bypasses
