def create_generic_handlers(example_svc, admin_svc, metrics_svc):
    """Create generic method handlers for all services."""

    class GenericHandler(grpc.GenericRpcHandler):
        def __init__(self):
            self._handlers = {
                # Health (no auth)
                "/grpc.health.v1.Health/Check": grpc.unary_unary_rpc_method_handler(
                    lambda req, ctx: b'{"status": "SERVING"}'
                ),
                # Example service (requires auth)
                "/example.v1.ExampleService/GetResource": grpc.unary_unary_rpc_method_handler(
                    example_svc.get_resource
                ),
                "/example.v1.ExampleService/ListResources": grpc.unary_unary_rpc_method_handler(
                    example_svc.list_resources
                ),
                # Admin service (bypasses auth - WARNING)
                "/admin/v1.AdminService/GetServerStatus": grpc.unary_unary_rpc_method_handler(
                    admin_svc.get_server_status
                ),
                "/admin/v1.AdminService/FlushCache": grpc.unary_unary_rpc_method_handler(
                    admin_svc.flush_cache
                ),
                "/admin/v1.AdminService/GetConfig": grpc.unary_unary_rpc_method_handler(
                    admin_svc.get_config
                ),
                # Metrics (bypasses auth)
                "/metrics/v1.MetricsService/GetMetrics": grpc.unary_unary_rpc_method_handler(
                    metrics_svc.get_metrics
                ),
            }

        def service(self, handler_call_details):
            return self._handlers.get(handler_call_details.method)

    return [GenericHandler()]


def create_server(
    port: int = 50051,
    max_workers: int = 10,
    auth_secret_key: str = None,
    rate_limit_max_requests: int = 100,
    rate_limit_window_seconds: int = 60,
) -> grpc.Server:
    """
    Create and configure the gRPC server with all interceptors.

    Interceptor order (outermost to innermost):
    1. LoggingInterceptor - logs all calls
    2. RateLimitInterceptor - prevents abuse
    3. AuthenticationInterceptor - validates tokens (with bypass config)
    """

    # Initialize components
    token_validator = TokenValidator(secret_key=auth_secret_key)
    rate_limiter = RateLimiter(
        max_requests=rate_limit_max_requests,
        window_seconds=rate_limit_window_seconds,
    )

    # Auth bypass configuration
    bypass_config = AuthBypassConfig(
        exact_paths={
            "/grpc.health.v1.Health/Check",
            "/grpc.health.v1.Health/Watch",
        },
        prefix_paths={
            "/grpc.reflection.",
        },
        operational_prefixes={
            "/health",
            "/metrics",
            "/admin/",  # ⚠️ SECURITY WARNING: See class docstring
        },
    )

    # Create interceptors (applied in reverse order - last in list is outermost)
    auth_interceptor = AuthenticationInterceptor(
        token_validator=token_validator,
        bypass_config=bypass_config,
    )
    rate_limit_interceptor = RateLimitInterceptor(
        rate_limiter=rate_limiter,
        bypass_config=bypass_config,
    )
    logging_interceptor = LoggingInterceptor()

    # Interceptors are applied outermost-first
    interceptors = [
        logging_interceptor,       # 1st: log everything
        rate_limit_interceptor,    # 2nd: rate limiting
        auth_interceptor,          # 3rd: authentication
    ]

    # Create server
    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=max_workers),
        interceptors=interceptors,
        options=[
            ("grpc.max_send_message_length", 50 * 1024 * 1024),  # 50MB
            ("grpc.max_receive_message_length", 50 * 1024 * 1024),
            ("grpc.keepalive_time_ms", 30000),
            ("grpc.keepalive_timeout_ms", 10000),
            ("grpc.keepalive_permit_without_calls", True),
        ],
    )

    # Create service handlers
    example_service = ExampleServiceHandler()
    admin_service = AdminServiceHandler()
    metrics_service = MetricsServiceHandler()

    # Register handlers
    handlers = create_generic_handlers(example_service, admin_service, metrics_service)
    for handler in handlers:
        server.add_generic_rpc_handlers([handler])

    # Bind port
    server.add_insecure_port(f"[::]:{port}")

    logger.info(f"Server configured on port {port}")
    logger.info(f"Interceptor chain: Logging → RateLimit → Authentication")

    return server, token_validator


